GameStateManager = {}

local curState = nil

local classMap = {
    [tostring(Define.GameStatus.WaitPlayer)] = WaitPlayerState,
    [tostring(Define.GameStatus.WaitPlayerCountDown)] = WaitPlayerCountDownState,
    [tostring(Define.GameStatus.WaitGameStart)] = WaitGameStartState,
    [tostring(Define.GameStatus.GameRunning)] = GameRunningState,
    [tostring(Define.GameStatus.GameEnd)] = GameEndState,
}

function GameStateManager:changeState(state)
    local class = classMap[tostring(state)]
    if not class then
        LogUtil.log("GameStateManager:changeState not class", LogUtil.LogLevel.Error)
        return
    end

    if curState then
        curState:leave()
    end

    curState = class.new()

    if curState then
        curState:enter()
    end

    LogUtil.log("GameStateManager:changeState " .. state)
end

function GameStateManager:init()
    self:changeState(Define.GameStatus.WaitPlayer)
end

function GameStateManager:onTick(ticks)
    if ticks % (1 * GameMatch.tickPerSecond) ~= 0 then
        return
    end

    if curState then
        curState:update()
    end
end

function GameStateManager:onPlayerReady(player)
    if curState then
        curState:onPlayerReady(player)
    end
end

function GameStateManager:getGameState()
    if curState then
        return curState.GameStatus
    end
    return Define.GameStatus.Unknown
end

return GameStateManager